import React, { useState, useEffect, useCallback } from 'react';
import { Container, Row, Col, Card, Button, ProgressBar, Table, Alert, Badge } from 'react-bootstrap';
import { LinkContainer } from 'react-router-bootstrap';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ML_PER_GLASS = 250;

const Dashboard = () => {
  const { token, authFetch } = useAuth();
  const navigate = useNavigate();
  const [payload, setPayload] = useState(null);
  const [error, setError] = useState('');

  const load = useCallback(async () => {
    const res = await authFetch('/api/profile');
    if (res.status === 401) {
      navigate('/login', { state: { from: { pathname: '/dashboard' } } });
      return;
    }
    const data = await res.json();
    if (!res.ok) {
      setError(data.error || 'Could not load dashboard');
      return;
    }
    setError('');
    setPayload(data);
  }, [authFetch, navigate]);

  useEffect(() => {
    if (!token) {
      navigate('/login', { state: { from: { pathname: '/dashboard' } } });
      return;
    }
    load();
  }, [token, navigate, load]);

  if (!payload) {
    return (
      <Container className="mt-4 py-5">
        {error ? <Alert variant="danger">{error}</Alert> : <p className="text-muted">Loading…</p>}
      </Container>
    );
  }

  const { user, profile, water_today_ml, water_goal_ml, recent_exercise } = payload;
  const displayName = [user?.first_name, user?.last_name].filter(Boolean).join(' ') || user?.email || 'User';
  const bmi = profile?.bmi ?? null;
  const dailyCal = profile?.daily_calories_needed ?? 2000;
  const waterGoalGlasses = Math.round(water_goal_ml / ML_PER_GLASS);
  const caloriesConsumed = 0;
  const proteinGoal = Math.round((dailyCal * 0.3) / 4);
  const carbsGoal = Math.round((dailyCal * 0.4) / 4);
  const fatsGoal = Math.round((dailyCal * 0.3) / 9);

  const getBMICategory = (val) => {
    if (val == null) return { category: '—', color: 'secondary' };
    if (val < 18.5) return { category: 'Underweight', color: 'info' };
    if (val < 25) return { category: 'Normal', color: 'success' };
    if (val < 30) return { category: 'Overweight', color: 'warning' };
    return { category: 'Obese', color: 'danger' };
  };

  const bmiInfo = getBMICategory(bmi);

  return (
    <div>
      <div className="dashboard-header">
        <Container>
          <h1 className="mb-0">Your Health Dashboard</h1>
          <p className="lead mb-0">Hi {displayName} — track nutrition and fitness</p>
        </Container>
      </div>

      <Container className="mt-4">
        {error && <Alert variant="danger">{error}</Alert>}

        <Alert variant="info" className="mb-4">
          <p className="mb-0">
            Log water and exercise from the quick actions below. Run <strong>Get Diet Recommendation</strong> on the
            Diet Plan page while logged in to save your BMI category and calorie target for reports and the developer
            dashboard.
          </p>
        </Alert>

        <Row className="mb-4">
          <Col md={3}>
            <Card className="stat-card">
              <Card.Body className="text-center">
                <h5 className="text-muted">Weight (profile)</h5>
                <h2>{profile?.weight != null ? `${profile.weight} kg` : '—'}</h2>
              </Card.Body>
            </Card>
          </Col>
          <Col md={3}>
            <Card className="stat-card">
              <Card.Body className="text-center">
                <h5 className="text-muted">BMI</h5>
                <h2>{bmi ?? '—'}</h2>
                <Badge bg={bmiInfo.color}>{bmiInfo.category}</Badge>
              </Card.Body>
            </Card>
          </Col>
          <Col md={3}>
            <Card className="stat-card">
              <Card.Body className="text-center">
                <h5 className="text-muted">Calorie target</h5>
                <h2>{Math.round(dailyCal)}</h2>
                <small>kcal / day (from plan)</small>
              </Card.Body>
            </Card>
          </Col>
          <Col md={3}>
            <Card className="stat-card">
              <Card.Body className="text-center">
                <h5 className="text-muted">Water today</h5>
                <h2>{(water_today_ml / ML_PER_GLASS).toFixed(1)}</h2>
                <small>of {waterGoalGlasses} glasses</small>
              </Card.Body>
            </Card>
          </Col>
        </Row>

        <Row className="mb-4">
          <Col md={6}>
            <Card>
              <Card.Header>
                <h5 className="mb-0">Daily goals (macros)</h5>
              </Card.Header>
              <Card.Body>
                <div className="mb-3">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Calories (logged meals not tracked yet)</span>
                    <span>
                      {caloriesConsumed} / {Math.round(dailyCal)}
                    </span>
                  </div>
                  <ProgressBar
                    now={dailyCal ? (caloriesConsumed / dailyCal) * 100 : 0}
                    variant="success"
                  />
                </div>
                <div className="mb-3">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Protein</span>
                    <span>0g / {proteinGoal}g</span>
                  </div>
                  <ProgressBar now={0} variant="info" />
                </div>
                <div className="mb-3">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Carbohydrates</span>
                    <span>0g / {carbsGoal}g</span>
                  </div>
                  <ProgressBar now={0} variant="warning" />
                </div>
                <div className="mb-3">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Fats</span>
                    <span>0g / {fatsGoal}g</span>
                  </div>
                  <ProgressBar now={0} variant="danger" />
                </div>
                <div className="mb-1">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Water</span>
                    <span>
                      {water_today_ml} ml / {water_goal_ml} ml
                    </span>
                  </div>
                  <ProgressBar
                    now={water_goal_ml ? Math.min(100, (water_today_ml / water_goal_ml) * 100) : 0}
                    variant="primary"
                  />
                </div>
              </Card.Body>
            </Card>
          </Col>
          <Col md={6}>
            <Card>
              <Card.Header>
                <h5 className="mb-0">Diet plan snapshot</h5>
              </Card.Header>
              <Card.Body>
                {profile ? (
                  <>
                    <p>
                      <strong>Category:</strong> {profile.bmi_category ?? '—'}
                    </p>
                    <p>
                      <strong>Activity:</strong> {profile.activity_level ?? '—'}
                    </p>
                    <p>
                      <strong>Goal:</strong> {profile.goal ?? '—'}
                    </p>
                    {profile.dietary_notes ? (
                      <p className="small text-muted mb-0">
                        <strong>Needs / notes:</strong> {profile.dietary_notes}
                      </p>
                    ) : null}
                  </>
                ) : (
                  <p className="text-muted mb-0">No saved plan yet. Use Diet Plan while logged in.</p>
                )}
              </Card.Body>
            </Card>
          </Col>
        </Row>

        <Row className="mb-4">
          <Col md={12}>
            <Card>
              <Card.Header>
                <h5 className="mb-0">Recent exercise</h5>
              </Card.Header>
              <Card.Body>
                {recent_exercise && recent_exercise.length > 0 ? (
                  <Table hover size="sm" className="mb-0">
                    <thead>
                      <tr>
                        <th>Activity</th>
                        <th>Minutes</th>
                        <th>Calories</th>
                        <th>When</th>
                      </tr>
                    </thead>
                    <tbody>
                      {recent_exercise.map((row) => (
                        <tr key={row.id}>
                          <td>{row.activity_type}</td>
                          <td>{row.duration_minutes}</td>
                          <td>{row.calories_burned != null ? row.calories_burned : '—'}</td>
                          <td>{new Date(row.logged_at).toLocaleString()}</td>
                        </tr>
                      ))}
                    </tbody>
                  </Table>
                ) : (
                  <p className="text-muted mb-0">No sessions yet.</p>
                )}
              </Card.Body>
            </Card>
          </Col>
        </Row>

        <Card className="mb-4">
          <Card.Header>
            <h5 className="mb-0">Quick actions</h5>
          </Card.Header>
          <Card.Body>
            <Row>
              <Col md={3} className="text-center mb-3">
                <LinkContainer to="/diet-form">
                  <Button variant="primary" className="w-100">
                    Update Diet Plan
                  </Button>
                </LinkContainer>
              </Col>
              <Col md={3} className="text-center mb-3">
                <LinkContainer to="/water">
                  <Button variant="success" className="w-100">
                    Log Water Intake
                  </Button>
                </LinkContainer>
              </Col>
              <Col md={3} className="text-center mb-3">
                <LinkContainer to="/exercise">
                  <Button variant="info" className="w-100">
                    Track Exercise
                  </Button>
                </LinkContainer>
              </Col>
              <Col md={3} className="text-center mb-3">
                <LinkContainer to="/reports">
                  <Button variant="warning" className="w-100">
                    View Reports
                  </Button>
                </LinkContainer>
              </Col>
            </Row>
          </Card.Body>
        </Card>
      </Container>
    </div>
  );
};

export default Dashboard;
